// Simple test to verify the date parsing logic without running the full test suite
const { parseISO, isValid } = require('date-fns');

const guessDateFromText = (text) => {
    // Try to get a date from a ISO format (e.g. "2014-02-11T11:30:30")
    const isoDate = parseISO(text);
    if (isValid(isoDate)) {
        return isoDate;
    }

    // Try to parse yyyy/mm/dd or yyyy/m/d format
    const ymdMatch = text.match(/^(\d{4})\/(\d{1,2})\/(\d{1,2})$/);
    if (ymdMatch) {
        const [, year, month, day] = ymdMatch;
        const date = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
        if (isValid(date)) {
            return date;
        }
    }

    // Try to get a date from a valid string format (e.g. "Jun 9, 2022", "mm/dd/yyyy")
    const textToDate = new Date(text);
    if (isValid(textToDate)) {
        return textToDate;
    }
};

// Test cases
const tests = [
    { input: 'Jun 9, 2022', expected: new Date(2022, 5, 9) },
    { input: '2014-02-11T11:30:30', expected: new Date(2014, 1, 11, 11, 30, 30) },
    { input: '2023/12/3', expected: new Date(2023, 11, 3) },
    { input: '03/12/2023', expected: new Date(2023, 2, 12) },
    { input: 'random string to make it fail', expected: undefined },
];

console.log('Testing guessDateFromText implementation:\n');

tests.forEach(({ input, expected }) => {
    const result = guessDateFromText(input);

    if (expected === undefined) {
        const pass = result === undefined;
        console.log(`${pass ? '✓' : '✗'} guessDateFromText('${input}') => ${result} (expected undefined)`);
    } else {
        const pass = result && result.getTime() === expected.getTime();
        console.log(`${pass ? '✓' : '✗'} guessDateFromText('${input}')`);
        if (!pass) {
            console.log(`  Expected: ${expected}`);
            console.log(`  Got:      ${result}`);
        }
    }
});

